// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	// STRY0100152 
	if(isLoading){
		checkResponseRequired(newValue);
		return;
	}
	checkResponseRequired(newValue);

	function checkResponseRequired(newValue){
		// STRY0089415 
		var responseRequired = (g_form.getValue('provide_response') + '' == 'true');
		g_form.showFieldMsg('provide_response', responseRequired ? getMessage('Tasker - A review on this Task is required') : getMessage('Tasker - A review on this Task is optional'));
	}
}
